                cvssScore = cvssScore,
                affectedProduct = affectedProduct,
                daysOpen = calculateDaysOpen(detectedAt),
                detectedAt = detectedAt,
                patchPublicationDate = patchPublicationDate,
                status = vuln["status"]?.toString() ?: "open",
                hasException = false,
                exceptionReason = null
            )

